第2章 线性表
本章重点：顺序存储线性表的定义及基本操作，单链表的定义及基本操作，线性表的应用。难点：链表的理解及基本操作实现。


一、线性表的基本概念线性表是一种一对一的数据结构。每个元素只有一个直接前驱和一个直接后继。用数学形式表示：$$ L &#x3D; (a_1, a_2, …, a_n) $$
特性： - 有穷性：元素数量有限 - 一致性：所有元素类型相同 -序列性：存在先后次序 - 可重复性：值可重复，但位置唯一
抽象数据类型（ADT）定义：
ADT List&lt;T&gt; &#123;  数据对象 D: &#123; ai | 1 ≤ i ≤ n, ai 为 ElemType 类型 &#125;  数据关系 R: &lt;ai, ai+1&gt; | i=1...n-1  基本操作 P: clear, is_empty, size, get, set, add, remove_node, index_of&#125;


二、顺序存储结构2.1 定义顺序表使用 数组 存储线性表元素：$$ Loc(a_{i+1}) &#x3D; Loc(a_0) + i  imes c $$
特点： - 元素物理位置连续 - 可随机存取（O(1)） -插入&#x2F;删除需移动元素（O(n)）
2.2 C语言实现typedef char* ElementType;typedef struct &#123;    size_t _length;     // 元素个数    size_t _capacity;   // 当前容量    ElementType* _data; // 数据数组&#125; LList;

初始化void initiliaze(LList* list)&#123;    list-&gt;_capacity = 32;    list-&gt;_data = malloc(list-&gt;_capacity * sizeof(ElementType));    list-&gt;_length = 0;&#125;

判空与求长bool is_empty(LList* list)&#123; return list-&gt;_length == 0; &#125;size_t size(LList* list)&#123; return list-&gt;_length; &#125;

查找元素int index_of(LList* list, ElementType key)&#123;    for(int i=0;i&lt;list-&gt;_length;++i)        if(list-&gt;_data[i]==key) return i;    return -1;&#125;



顺序表插入算法（展开查看）

void add(LList* list, int idx, ElementType d)&#123;    if(list-&gt;_capacity &lt; list-&gt;_length + 1)&#123;        list-&gt;_capacity *= 2;        list-&gt;_data = realloc(list-&gt;_data, list-&gt;_capacity * sizeof(ElementType));    &#125;    for(size_t i=list-&gt;_length;i&gt;idx;--i)        list-&gt;_data[i] = list-&gt;_data[i-1];    list-&gt;_data[idx] = d;    ++list-&gt;_length;&#125;

#### 删除元素

ElementType remove_node(LList* list, int idx)&#123;    ElementType res = list-&gt;_data[idx];    for(size_t i=idx+1;i&lt;list-&gt;_length;++i)        list-&gt;_data[i-1] = list-&gt;_data[i];    --list-&gt;_length;    return res;&#125;

平均复杂度分析插入或删除平均需要移动约一半的元素：$$ T(n) &#x3D; O(n) $$

三、顺序表应用案例：课堂座位管理int main()&#123;    LList l;    initiliaze(&amp;l);    add(&amp;l,0,&quot;张一安&quot;);    add(&amp;l,1,&quot;李二同&quot;);    add(&amp;l,1,&quot;林三玲&quot;);    set(&amp;l,0,&quot;王四刚&quot;);    remove_node(&amp;l,1);    print_all_data(&amp;l);&#125;


四、链式存储结构4.1 定义链表使用指针表示逻辑关系，不要求内存连续。
struct Node &#123;    ElementType _data;    struct Node* _next;&#125;;

带头结点的单链表定义：
typedef struct &#123;    size_t _length;    struct Node* _head;    struct Node* _tail;&#125; LList;

4.2 基本操作插入void add(LList* list, int idx, ElementType d)&#123;    if(idx == 0) push_front(list,d);    else if(idx == list-&gt;_length) push_back(list,d);    else &#123;        struct Node* p = _get_node(list, idx-1);        struct Node* q = malloc(sizeof(struct Node));        q-&gt;_data = d;        q-&gt;_next = p-&gt;_next;        p-&gt;_next = q;        ++list-&gt;_length;    &#125;&#125;

删除ElementType remove_node(LList* list, int idx)&#123;    struct Node* p = _get_node(list, idx-1);    struct Node* q = p-&gt;_next;    p-&gt;_next = q-&gt;_next;    ElementType res = q-&gt;_data;    free(q);    --list-&gt;_length;    return res;&#125;



带头结点的优势

-   无论空表或非空表，结构统一\
-   插入删除无需特殊判断\
-   简化代码逻辑\



五、链表算法应用1️⃣ 删除所有值为x的元素（O(n)）void delnode1(SqList *L, ElemType x)&#123;    int k=0;    for(int i=0;i&lt;L-&gt;length;i++)        if(L-&gt;data[i]!=x)            L-&gt;data[k++] = L-&gt;data[i];    L-&gt;length = k;&#125;

2️⃣ 单链表逆置void Reverse(LinkNode *L)&#123;    LinkNode *p=L-&gt;next,*q;    L-&gt;next=NULL;    while(p!=NULL)&#123;        q=p-&gt;next;        p-&gt;next=L-&gt;next;        L-&gt;next=p;        p=q;    &#125;&#125;

3️⃣ 拆分链表void split(LinkNode *L, LinkNode *L1, LinkNode *L2)&#123;    LinkNode *p=L-&gt;next,*r1=L;    L2=malloc(sizeof(LinkNode));    L2-&gt;next=NULL;    while(p)&#123;        r1-&gt;next=p; r1=p; p=p-&gt;next;        LinkNode* q=p-&gt;next;        p-&gt;next=L2-&gt;next; L2-&gt;next=p;        p=q;    &#125;    r1-&gt;next=NULL;&#125;


六、循环链表与双链表
循环链表：尾指针 _tail-&gt;_next = _head
双链表：每个结点包含 _prev 与 _next
循环双链表：头尾相连，双向遍历

struct Node &#123;    ElementType _data;    struct Node *_next;    struct Node *_prev;&#125;;


七、顺序表与链表对比  特性        顺序表    链表

  存储方式    连续      离散  随机访问    ✅ O(1)   ❌ O(n)  插入&#x2F;删除   ❌ O(n)   ✅ O(1)  存储密度    高        较低

八、线性表的总结
抽象定义：有限序列 $(a_1, a_2, …, a_n)$\
存储实现：顺序结构、链式结构\
操作：插入、删除、查找、遍历、逆置、拆分\
应用：学生表、员工表、图书数据管理等


💡 学习建议： 先理解逻辑结构（顺序 vs链式），再通过代码体会物理存储的差异。多动手实现，才能真正掌握线性表的核心思想。
